def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 20):
            if j % 5 == 0 and j % 3 == 0:
                factor = 1.5
            elif j % 4 == 0:
                factor = 1.3
            elif j % 3 == 0:
                factor = 1.2
            elif j % 2 == 0:
                factor = 1.1
            else:
                factor = 0.85
            increment = factor * ((ratio) ** j) / (j ** 2)
            if j % 7 == 0:
                increment *= 1.1
            if j % 11 == 0:
                increment -= 0.02 * j
            score += increment
        remain_ratio = (capacity - item) / capacity
        if remain_ratio < 0.01:
            score *= 3.0
        elif remain_ratio < 0.05:
            score *= 2.0
        elif remain_ratio < 0.15:
            score *= 1.3
        elif remain_ratio < 0.3:
            score *= 1.0
        else:
            score *= 0.6
        mods = [int(capacity) % x == 0 for x in [2,3,5,7,11,13]]
        if all(mods[:3]):
            score -= 0.15 * (capacity / 7)
        elif mods[2] and mods[3]:
            score -= 0.2 * (capacity / 12)
        elif mods[0] and mods[5]:
            score -= 0.1 * (capacity / 18)
        else:
            score -= 0.04 * (capacity / 25)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 3 * threshold:
                penalty += 0.15 * k
            elif diff < 5 * threshold:
                penalty -= 0.1 * k
            else:
                penalty -= 0.07 * k
            if k % 2 == 0 and diff < threshold:
                penalty += 0.05 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 5):
                part = capacity / m
                margin = 0.025 * part
                if abs(part - item) < margin:
                    score *= (1 + 0.04 * m)
                elif abs(part*0.9 - item) < margin:
                    score *= (1 + 0.02 * m)
                elif abs(part*1.1 - item) < margin:
                    score *= (1 + 0.02 * m)
        if score > 3.5:
            for n in range(1, 4):
                if abs(item - capacity / (2 ** n)) < 0.01 * capacity:
                    score *= (1 + 0.1 / n)
                elif abs(item - capacity / (3 ** n)) < 0.015 * capacity:
                    score *= (1 + 0.08 / n)
        priorities[i] = score
    return priorities
